import React, { useState, useEffect } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

// Icon SVG tối giản, màu đơn sắc #003366
const Icons = {
  Edit: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="2"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>,
  Save: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="white" strokeWidth="2"><path d="M5 13l4 4L19 7" /></svg>,
  Delete: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="#d32f2f" strokeWidth="2"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
  Role: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="2"><path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
};

const StaffManager = () => {
  const { user } = useAuth();
  const { staffList, addStaff, deleteStaff, updatePassword, updateStaffInfo } = useData();

  // State
  const [formData, setFormData] = useState({ name: '', username: '', password: '' });
  const [editMode, setEditMode] = useState(null);
  const [editForm, setEditForm] = useState({});

  // Quyền hạn
  const isChief = user?.role === 'chief';
  const isReg = user?.role === 'reg';
  const isOp = user?.role === 'op';
  const canEditRoles = isChief || isReg || isOp;

  // Danh sách các vị trí chức năng (Functional Roles)
  const opRoles = ['ST', 'TT', 'CCS', 'CCO', 'CCA'];
  const regRoles = ['FFM', 'FFS', 'FFA'];

  // --- LOGIC XỬ LÝ ---

  const handleAdd = (e) => {
    e.preventDefault();
    if (!isChief) return alert("Chỉ Chief Administrator mới được tạo tài khoản!");
    if (!formData.name || !formData.username || !formData.password) return;
    
    // Mặc định tạo ra là staff, chưa có vị trí chức năng
    addStaff({ 
      ...formData, 
      role: 'staff', 
      positions: [], 
      baseUBI: 0, 
      ubiPercentage: 100 
    });
    setFormData({ name: '', username: '', password: '' });
  };

  const handleDelete = (id) => {
    if (!isChief) return alert("Chỉ Chief Administrator mới được xóa tài khoản!");
    if (window.confirm("Bạn có chắc chắn muốn xóa nhân sự này?")) deleteStaff(id);
  };

  const startEdit = (staff) => {
    setEditMode(staff.id);
    setEditForm({
      name: staff.name,
      phone: staff.phone || '',
      email: staff.email || '',
      department: staff.department || '',
      title: staff.title || '',
      role: staff.role || 'staff',
      positions: staff.positions || [], // Mảng chứa các vị trí ST, TT...
      baseUBI: staff.baseUBI || 0,
      ubiPercentage: staff.ubiPercentage || 100,
      status: staff.status || 'active'
    });
  };

  const handlePositionToggle = (pos) => {
    const currentPositions = editForm.positions || [];
    if (currentPositions.includes(pos)) {
      setEditForm({ ...editForm, positions: currentPositions.filter(p => p !== pos) });
    } else {
      setEditForm({ ...editForm, positions: [...currentPositions, pos] });
    }
  };

  const saveEdit = (id) => {
    updateStaffInfo(id, editForm);
    setEditMode(null);
    alert("Cập nhật thông tin thành công!");
  };

  const roleLabel = (r) => {
    switch(r) {
        case 'chief': return 'Chief Admin';
        case 'reg': return 'Regulatory Admin';
        case 'op': return 'Operational Admin';
        default: return 'Staff';
    }
  };

  return (
    <div style={{ paddingBottom: '40px' }}>
      <h2 style={{ color: '#003366', borderBottom: '2px solid #003366', paddingBottom: '10px' }}>Quản lý & Phân quyền Nhân sự</h2>

      {/* Form thêm mới (Chỉ Chief) */}
      {isChief && (
        <div style={{ background: '#fff', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 8px rgba(0,0,0,0.05)', marginBottom: '20px' }}>
          <h4 style={{ margin: '0 0 15px 0', color: '#003366' }}>+ Thêm nhân sự mới</h4>
          <form onSubmit={handleAdd} style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
            <input placeholder="Họ tên" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} required style={inputStyle} />
            <input placeholder="Username" value={formData.username} onChange={e => setFormData({ ...formData, username: e.target.value })} required style={inputStyle} />
            <input placeholder="Password" type="password" value={formData.password} onChange={e => setFormData({ ...formData, password: e.target.value })} required style={inputStyle} />
            <button type="submit" style={btnStyle('add')}>Tạo tài khoản</button>
          </form>
        </div>
      )}

      {/* Danh sách nhân sự */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '20px' }}>
        {staffList.map(staff => (
          <div key={staff.id} style={{ background: 'white', borderRadius: '8px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)', padding: '20px', border: editMode === staff.id ? '2px solid #003366' : '1px solid #eee' }}>
            
            {/* HEADERCARD: Tên và Role hệ thống */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '10px' }}>
              <div>
                <strong style={{ fontSize: '1.1rem', color: '#333' }}>{staff.name}</strong>
                <div style={{ fontSize: '0.85rem', color: '#666' }}>@{staff.username}</div>
              </div>
              <span style={{ 
                background: staff.role === 'chief' ? '#003366' : '#f0f2f5', 
                color: staff.role === 'chief' ? 'white' : '#333',
                padding: '4px 8px', borderRadius: '4px', fontSize: '0.75rem', fontWeight: 'bold' 
              }}>
                {roleLabel(staff.role)}
              </span>
            </div>

            {/* BODY: Chế độ Xem hoặc Sửa */}
            {editMode === staff.id ? (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                {/* 1. Thông tin cơ bản */}
                <div style={groupStyle}>
                  <label style={labelStyle}>Thông tin liên hệ</label>
                  <input value={editForm.name} onChange={e => setEditForm({...editForm, name: e.target.value})} placeholder="Họ tên" style={inputStyleFull} />
                  <div style={{display: 'flex', gap: '5px'}}>
                    <input value={editForm.phone} onChange={e => setEditForm({...editForm, phone: e.target.value})} placeholder="SĐT" style={inputStyleFull} />
                    <input value={editForm.email} onChange={e => setEditForm({...editForm, email: e.target.value})} placeholder="Email" style={inputStyleFull} />
                  </div>
                  <div style={{display: 'flex', gap: '5px'}}>
                    <input value={editForm.department} onChange={e => setEditForm({...editForm, department: e.target.value})} placeholder="Phòng ban" style={inputStyleFull} />
                    <input value={editForm.title} onChange={e => setEditForm({...editForm, title: e.target.value})} placeholder="Chức danh" style={inputStyleFull} />
                  </div>
                </div>

                {/* 2. Thẩm quyền: System Role (Chỉ Chief sửa được) */}
                {isChief && (
                  <div style={groupStyle}>
                    <label style={labelStyle}>Vai trò hệ thống (System Role)</label>
                    <select value={editForm.role} onChange={e => setEditForm({...editForm, role: e.target.value})} style={inputStyleFull}>
                      <option value="staff">Staff (Nhân viên)</option>
                      <option value="op">Operational Admin</option>
                      <option value="reg">Regulatory Admin</option>
                      <option value="chief">Chief Admin</option>
                    </select>
                  </div>
                )}

                {/* 3. Thẩm quyền: Functional Positions (Phân quyền theo user login) */}
                {(isOp || isChief || isReg) && (
                   <div style={groupStyle}>
                     <label style={labelStyle}>Xét vị trí (Functional Roles)</label>
                     <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                        {/* OP hoặc CHIEF được gán nhóm OP roles */}
                        {(isOp || isChief) && opRoles.map(r => (
                          <label key={r} style={checkboxLabelStyle}>
                            <input type="checkbox" 
                              checked={editForm.positions?.includes(r)} 
                              onChange={() => handlePositionToggle(r)} 
                            /> {r}
                          </label>
                        ))}
                        {/* REG hoặc CHIEF được gán nhóm REG roles */}
                        {(isReg || isChief) && regRoles.map(r => (
                          <label key={r} style={checkboxLabelStyle}>
                            <input type="checkbox" 
                              checked={editForm.positions?.includes(r)} 
                              onChange={() => handlePositionToggle(r)} 
                            /> {r}
                          </label>
                        ))}
                     </div>
                   </div>
                )}

                {/* 4. Tài chính (Chỉ Chief) */}
                {isChief && (
                  <div style={groupStyle}>
                    <label style={labelStyle}>Mức lương & UBI</label>
                    <div style={{display: 'flex', gap: '5px', alignItems: 'center'}}>
                       <input 
                         type="number" 
                         value={editForm.baseUBI} 
                         onChange={e => setEditForm({...editForm, baseUBI: Number(e.target.value)})} 
                         placeholder="UBI Định mức" 
                         style={inputStyleFull} 
                       />
                       <select 
                         value={editForm.ubiPercentage} 
                         onChange={e => setEditForm({...editForm, ubiPercentage: Number(e.target.value)})} 
                         style={{...inputStyleFull, width: '80px'}}
                       >
                         <option value={25}>25%</option>
                         <option value={50}>50%</option>
                         <option value={75}>75%</option>
                         <option value={100}>100%</option>
                       </select>
                    </div>
                    <small style={{color: '#666'}}>Thực lĩnh: {((editForm.baseUBI * editForm.ubiPercentage)/100).toLocaleString()} VNĐ</small>
                  </div>
                )}
                
                {/* 5. Trạng thái */}
                {isChief && (
                    <div style={groupStyle}>
                        <label style={labelStyle}>Trạng thái hoạt động</label>
                        <select value={editForm.status} onChange={e => setEditForm({...editForm, status: e.target.value})} style={inputStyleFull}>
                            <option value="active">Đang hoạt động</option>
                            <option value="suspended">Đình chỉ</option>
                        </select>
                    </div>
                )}

                {/* Action Buttons */}
                <div style={{ display: 'flex', gap: '10px', marginTop: '10px' }}>
                  <button onClick={() => saveEdit(staff.id)} style={btnStyle('save')}>
                    <Icons.Save /> Cập nhật mới
                  </button>
                  <button onClick={() => setEditMode(null)} style={btnStyle('cancel')}>Hủy</button>
                </div>
              </div>
            ) : (
              // --- VIEW MODE ---
              <div style={{ display: 'flex', flexDirection: 'column', height: '100%', justifyContent: 'space-between' }}>
                <div>
                   {(staff.positions && staff.positions.length > 0) && (
                     <div style={{ marginBottom: '8px' }}>
                       <div style={{ fontSize: '0.75rem', color: '#888', textTransform: 'uppercase' }}>Vị trí đảm nhiệm:</div>
                       <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', marginTop: '4px' }}>
                         {staff.positions.map(p => (
                           <span key={p} style={{ background: '#e6f7ff', color: '#003366', padding: '2px 6px', borderRadius: '4px', fontSize: '0.75rem', border: '1px solid #91d5ff' }}>{p}</span>
                         ))}
                       </div>
                     </div>
                   )}
                   
                   {/* Chỉ Chief hoặc chính chủ (nếu cần) mới thấy lương */}
                   {isChief && (
                     <div style={{ marginBottom: '8px', padding: '8px', background: '#f9f9f9', borderRadius: '4px' }}>
                       <div style={{ fontSize: '0.75rem', color: '#888' }}>UBI (Định mức / Thực tế):</div>
                       <strong style={{ color: '#28a745' }}>
                         {(staff.baseUBI || 0).toLocaleString()} / {((staff.baseUBI * (staff.ubiPercentage || 0))/100).toLocaleString()}
                       </strong>
                       <span style={{ fontSize: '0.75rem', marginLeft: '5px', color: '#666' }}>({staff.ubiPercentage}%)</span>
                     </div>
                   )}

                   <div style={{ fontSize: '0.85rem', color: '#555', marginTop: '10px' }}>
                      {staff.phone && <div>📞 {staff.phone}</div>}
                      {staff.email && <div>✉️ {staff.email}</div>}
                      {staff.status === 'suspended' && <div style={{color: 'red', fontWeight: 'bold'}}>⚠ ĐÃ ĐÌNH CHỈ</div>}
                   </div>
                </div>

                <div style={{ borderTop: '1px solid #eee', paddingTop: '10px', marginTop: '15px', display: 'flex', justifyContent: 'flex-end', gap: '8px' }}>
                   {canEditRoles && (
                     <button onClick={() => startEdit(staff)} style={btnStyle('edit')} title="Chỉnh sửa / Phân quyền">
                       <Icons.Edit /> Điều chỉnh
                     </button>
                   )}
                   {isChief && (
                     <button onClick={() => handleDelete(staff.id)} style={btnStyle('delete')} title="Xóa nhân sự">
                       <Icons.Delete />
                     </button>
                   )}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

// --- STYLES ---
const inputStyle = { padding: '10px', border: '1px solid #ccc', borderRadius: '4px', flex: '1' };
const inputStyleFull = { ...inputStyle, width: '100%', boxSizing: 'border-box' };
const groupStyle = { background: '#f8f9fa', padding: '10px', borderRadius: '6px', border: '1px solid #eee' };
const labelStyle = { display: 'block', fontSize: '0.75rem', color: '#666', marginBottom: '4px', textTransform: 'uppercase', fontWeight: 'bold' };
const checkboxLabelStyle = { display: 'flex', alignItems: 'center', gap: '4px', fontSize: '0.85rem', background: 'white', padding: '4px 8px', borderRadius: '4px', border: '1px solid #ddd', cursor: 'pointer' };

const btnStyle = (type) => {
  const base = { border: 'none', borderRadius: '4px', cursor: 'pointer', padding: '8px 12px', display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.9rem', fontWeight: '500', transition: 'all 0.2s' };
  switch(type) {
    case 'add': return { ...base, background: '#28a745', color: 'white' };
    case 'save': return { ...base, background: '#003366', color: 'white', flex: 1, justifyContent: 'center' };
    case 'cancel': return { ...base, background: '#6c757d', color: 'white' };
    case 'edit': return { ...base, background: 'transparent', border: '1px solid #003366', color: '#003366' };
    case 'delete': return { ...base, background: '#ffebee', color: '#d32f2f' };
    default: return base;
  }
};

export default StaffManager;
